 1	/**
 2	 * A simplified dropdown component using PatternFly, designed for basic dropdown needs. It supports customizable
 3	 * labels, items, accessibility options, and styling variants. The component is flexible, allowing for optional
 4	 * full-width display and an onSelect callback for additional interaction handling.
 5	 *
 6	 * @module simpleDropdown
 7	 */
 8	import React, { useState } from 'react';
 9	import {
10	  Dropdown,
11	  DropdownItem,
12	  DropdownList,
13	  MenuToggle,
14	  type MenuToggleElement,
15	  type MenuToggleProps
16	} from '@patternfly/react-core';
17	
18	interface SimpleDropdownItemProps {
19	  item: string;
20	  ouiaId?: number | string;
21	}
22	
23	interface SimpleDropdownProps {
24	  label: string;
25	  menuToggleOuiaId?: number | string;
26	  dropdownItems?: SimpleDropdownItemProps[];
27	  ariaLabel?: string;
28	  onSelect?: (item: string) => void;
29	  variant?: MenuToggleProps['variant'];
30	  isFullWidth?: boolean;
31	}
32	
33	const SimpleDropdown: React.FC<SimpleDropdownProps> = ({
34	  label,
35	  menuToggleOuiaId,
36	  dropdownItems,
37	  ariaLabel = 'Dropdown menu',
38	  onSelect = Function.prototype,
39	  variant,
40	  isFullWidth
41	}) => {
42	  const [isOpen, setIsOpen] = useState(false);
43	
44	  return (
45	    <Dropdown
46	      isOpen={isOpen}
47	      onOpenChange={isOpen => setIsOpen(isOpen)}
48	      onSelect={() => {
49	        setIsOpen(false);
50	      }}
51	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
52	        <MenuToggle
53	          isFullWidth={isFullWidth}
54	          ref={toggleRef}
55	          isExpanded={isOpen}
56	          onClick={() => setIsOpen(!isOpen)}
57	          variant={variant}
58	          aria-label={ariaLabel}
59	          isDisabled={!dropdownItems || dropdownItems.length === 0}
60	          data-ouia-component-id={menuToggleOuiaId}
61	        >
62	          {label}
63	        </MenuToggle>
64	      )}
65	    >
66	      <DropdownList>
67	        {Array.isArray(dropdownItems) &&
68	          dropdownItems.map(({ item, ouiaId }) => (
69	            <DropdownItem key={item} onClick={() => onSelect(item)} ouiaId={ouiaId}>
70	              {item}
71	            </DropdownItem>
72	          ))}
73	      </DropdownList>
74	    </Dropdown>
75	  );
76	};
77	
78	export { SimpleDropdown as default, SimpleDropdown, type SimpleDropdownProps };

